.container-wrapper {
  container-type: inline-size;
  container-name: card-container;
}
.responsive-card {
  display: flex;
  flex-direction: column;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
}
.card-img {
  width: 100%;
  height: auto;
  display: block;
}
.card-content {
  padding: 16px;
}
@container card-container (min-width: 400px) {
  .responsive-card {
    flex-direction: row;
  }
  .card-img {
    width: 200px;
    object-fit: cover;
  }
}

